navigation/global-navigation.css"><link rel="preload" as="script" href="/marketingtech/d4d114c60e50/a0e989131fd5/launch-5dd5dd2177e6.min.js"><link rel="stylesheet" href="https://use.typekit.net/hah7vzn.css"><link rel="stylesheet" href="/libs/blocks/global-navigation/base.css"><script type="application/ld+json">{"@context":"https://schema.org","@type":"BreadcrumbList","itemListElement":[{"@type":"ListItem","position":1,"name":"Home","item":"https://www.adobe.com/"},{"@type":"ListItem","position":2,"name":"Adobe Creative Cloud","item":"/creativecloud/"},{"@type":"ListItem","position":3,"name":"Adobe Lightroom","item":"/products/photoshop-lightroom/"}]}</script><link rel="preload" as="script" crossorigin="anonymous" href="/libs/blocks/notification/notification.js"><link rel="stylesheet" href="/libs/blocks/notification/notification.css"><link rel="preload" as="script" crossorigin="anonymous" href="/libs/blocks/section-metadata/section-metadata.js"><link rel="stylesheet" href="https://prod.adobeccstatic.com/unav/1.5/UniversalNav.css"><link rel="stylesheet" type="text/css" href="https://prod.adobeccstatic.com/unav/1.5/layout.bundle.css"><link rel="stylesheet" type="text/css" href="https://prod.adobeccstatic.com/unav/1.5/popover.bundle.css"><link rel="stylesheet" type="text/css" href="https://prod.adobeccstatic.com/unav/1.5/profile.bundle.css"><link rel="stylesheet" href="/libs/blocks/carousel/carousel.css"><link rel="stylesheet" href="/libs/blocks/tabs/tabs.css"><link rel="stylesheet" href="/libs/blocks/editorial-card/editorial-card.css"><link rel="stylesheet" href="/libs/styles/rounded-corners.css"><link rel="preload" as="script" crossorigin="anonymous" href="/libs/blocks/aside/aside.js"><link rel="stylesheet" href="/libs/blocks/aside/aside.css"><link rel="preload" as="script" crossorigin="anonymous" href="/libs/blocks/accordion/accordion.js"><link rel="stylesheet" href="/libs/blocks/accordion/accordion.css"><script type="application/ld+json">{"@context":"https://schema.org","@type":"FAQPage","mainEntity":[[{"@type":"Question","name":"\n      What is Lightroom?\n    ","acceptedAnswer":{"text":"Lightroom is the cloud-based service that gives you everything you need to create, edit, organize, store, and share your photos across any device.","@type":"Answer"}},{"@type":"Question","name":"\n      Can I buy Lightroom as a standalone app?\n    ","acceptedAnswer":{"text":"Yes, you can buy Lightroom as a single app. Purchase Lightroom now.","@type":"Answer"}},{"@type":"Question","name":"\n      How much does Lightroom cost?\n    ","acceptedAnswer":{"text":"You can purchase Lightroom with an annual plan starting at US$11.99/mo  for the annual billed monthly plan or .","@type":"Answer"}},{"@type":"Question","name":"\n      How much cloud storage comes with Lightroom?\n    ","acceptedAnswer":{"text":"The Lightroom plan comes with 1TB. You can always add more storage to your plan from your Adobe account. Learn how to upgrade your storage plan.","@type":"Answer"}},{"@type":"Question","name":"\n      Can I install Lightroom on multiple devices?\n    ","acceptedAnswer":{"text":"Yes, your individual license lets you install Lightroom on more than one computer. You can activate it on two but only use it on one computer at a time.","@type":"Answer"}},{"@type":"Question","name":"\n      How do I use Lightroom?\n    ","acceptedAnswer":{"text":"Learn the basics or refine your skills with Lightroom tutorials designed to inspire. Explore all Lightroom tutorials.","@type":"Answer"}},{"@type":"Question","name":"\n      How do I update Lightroom?\n    ","acceptedAnswer":{"text":"You can update Lightroom within your Adobe account. Learn how to update Lightroom.","@type":"Answer"}},{"@type":"Question","name":"\n      Is Lightroom free on iPhone?\n    ","acceptedAnswer":{"text":"Yes, Lightroom for mobile is a free app for iOS and Android that gives you a powerful yet simple solution for capturing, editing, and sharing photos. You can also upgrade to premium features and work across any device. Learn how to upgrade to premium features.","@type":"Answer"}},{"@type":"Question","name":"\n      What’s the difference between Lightroom and Lightroom Classic?\n    ","acceptedAnswer":{"text":"Both Lightroom and Lightroom Classic offer most of the same features, but Lightroom lets you edit and organize your photos across desktop, mobile, and web, while Lightroom Classic is optimized for desktop use. Lightroom Classic is included in the Lightroom plan. Find out more about the difference between Lightroom and Lightroom Classic.","@type":"Answer"}},{"@type":"Question","name":"\n      What’s the difference between Lightroom and Photoshop?\n    ","acceptedAnswer":{"text":"Lightroom and Photoshop are powerful image editing tools. Use Lightroom to easily edit your photos to make them match your vision. For more transformational edits like compositing or fine retouching, try Photoshop. Learn more about the difference between Lightroom and Photoshop.","@type":"Answer"}},{"@type":"Question","name":"\n      What is Lightroom CC?\n    ","acceptedAnswer":{"text":"When Lightroom first launched it was called Lightroom CC. We have since renamed it to just Lightroom.","@type":"Answer"}},{"@type":"Question","name":"\n      Is there a student discount for Lightroom?\n    ","acceptedAnswer":{"text":"Yes, students and teachers can get Lightroom as part of the Creative Cloud Pro plan for a reduced price of  for the first year. The plan features 20+ desktop and mobile apps including Lightroom, Photoshop, Acrobat Pro, Illustrator, InDesign, XD, Premiere, and more. At the end of the first year, the subscription will be automatically billed at the standard rate, currently , unless you elect to change or cancel your subscription. Learn more about the Creative Cloud Pro plan for students and teachers.","@type":"Answer"}},{"@type":"Question","name":"\n      How do I cancel a Lightroom subscription?\n    ","acceptedAnswer":{"text":"To cancel your Lightroom subscription, navigate to your Adobe account page. Locate your plan name and click Manage Plans. Then click Cancel Plan. Indicate your cancellation reason, and then click continue. Follow the onscreen instructions to finish your cancellation. Get step-by-step cancellation instructions.","@type":"Answer"}},{"@type":"Question","name":"\n      Are the new Lightroom features also available on the web?\n    ","acceptedAnswer":{"text":"Yes. You can now access the power of AI on Lightroom for the web (Lightroom.adobe.com), starting with our selective adjustment tools. AI masking for Select Subject, Sky, and Background are available on web, plus new Adaptive Presets including Whiten Teeth, Glamour, and more.","@type":"Answer"}}]]}</script></head>
